@@ -1106,6 +1106,18 @@ static bool tryToOptimizeStoreOfAllocationToGlobal(GlobalVariable *GV,
   if (!allUsesOfLoadedValueWillTrapIfNull(GV))
     return false;

+  // Check if any store or load to the global is atomic. Atomic operations
+  // have stricter memory ordering semantics that may not be preserved by
+  // the transformation.
+  SmallVector<Value *, 4> Guses;
